import{_ as e,o as d,c as o,a2 as a}from"./chunks/framework.QoSTM79V.js";const s=JSON.parse('{"title":"<模块名> 使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/templates/module-readme.md","filePath":"mango-pmo/templates/module-readme.md"}'),r={name:"mango-pmo/templates/module-readme.md"};function l(c,t,h,n,i,p){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="模块名-使用说明" tabindex="-1">&lt;模块名&gt; 使用说明 <a class="header-anchor" href="#模块名-使用说明" aria-label="Permalink to &quot;&lt;模块名&gt; 使用说明&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p>说明模块定位、面向的使用者、解决的问题，以及业务开发者应该保存或调用什么。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><p>用表格列出主要能力、用途和常用入口。入口可以是后端依赖、HTTP API、Java API、前端组件、CLI 命令或管理页面。</p><h2 id="_3-接入方式" tabindex="-1">3. 接入方式 <a class="header-anchor" href="#_3-接入方式" aria-label="Permalink to &quot;3. 接入方式&quot;">​</a></h2><p>说明开发时依赖、部署时依赖、前端包、CLI module、starter、模板或配置入口。开发依赖和部署依赖必须分清。</p><p>登记本模块依赖的 Mango 能力说明，至少列出能力名称、使用位置和文档入口：</p><table tabindex="0"><thead><tr><th>Mango 能力</th><th>本模块使用位置</th><th>文档入口</th></tr></thead><tbody><tr><td>Persistence 持久化</td><td><code>&lt;Service / Mapper / Controller&gt;</code></td><td><code>&lt;mango-infra-persistence README 或能力地图链接&gt;</code></td></tr><tr><td><code>&lt;平台或前端能力&gt;</code></td><td><code>&lt;使用位置&gt;</code></td><td><code>&lt;对应模块 README&gt;</code></td></tr></tbody></table><h2 id="_4-配置说明" tabindex="-1">4. 配置说明 <a class="header-anchor" href="#_4-配置说明" aria-label="Permalink to &quot;4. 配置说明&quot;">​</a></h2><p>列出关键配置入口和配置来源；默认值以配置类、模板或 PMO 规则源为准。</p><p>配置项必须写到字段级：</p><table tabindex="0"><thead><tr><th>配置入口</th><th>字段 / Key</th><th>默认值</th><th>含义</th><th>影响行为</th><th>源码入口</th></tr></thead><tbody><tr><td><code>application.yml</code></td><td><code>mango.&lt;module&gt;.enabled</code></td><td><code>&lt;默认值&gt;</code></td><td><code>&lt;含义&gt;</code></td><td><code>&lt;开启或关闭什么&gt;</code></td><td><code>&lt;配置类&gt;</code></td></tr><tr><td><code>&lt;运行时配置 API / 管理页&gt;</code></td><td><code>&lt;字段&gt;</code></td><td><code>&lt;默认值&gt;</code></td><td><code>&lt;含义&gt;</code></td><td><code>&lt;影响链路&gt;</code></td><td><code>&lt;Controller / Service&gt;</code></td></tr></tbody></table><h2 id="_5-api-与扩展" tabindex="-1">5. API 与扩展 <a class="header-anchor" href="#_5-api-与扩展" aria-label="Permalink to &quot;5. API 与扩展&quot;">​</a></h2><p>列出对业务开发者有用的公开 API、事件、SPI、注解、组件或扩展点。完整 HTTP 入参和返回字段优先由 OpenAPI 承担，README 只写常用入口和关键字段。</p><h2 id="_6-数据与初始化" tabindex="-1">6. 数据与初始化 <a class="header-anchor" href="#_6-数据与初始化" aria-label="Permalink to &quot;6. 数据与初始化&quot;">​</a></h2><p>说明 migration、默认数据、资源清单、菜单、字典或初始化方式。 只写本模块的具体表、数据、资源和入口；长期数据库、事务和初始化规则只链接 <code>mango-pmo/rules/**</code>。</p><p>有持久化或默认数据时，必须登记：</p><table tabindex="0"><thead><tr><th>类型</th><th>位置</th><th>初始化内容</th><th>幂等键 / 唯一键</th><th>生效时机</th></tr></thead><tbody><tr><td>Flyway migration</td><td><code>&lt;db/migration/...&gt;</code></td><td><code>&lt;表 / 默认数据&gt;</code></td><td><code>&lt;唯一键&gt;</code></td><td><code>&lt;应用启动 / 模块启用&gt;</code></td></tr><tr><td>资源清单</td><td><code>&lt;META-INF/mango/resource-manifest.json&gt;</code></td><td><code>&lt;菜单 / 权限&gt;</code></td><td><code>&lt;appCode + moduleCode + menuCode&gt;</code></td><td><code>&lt;资源同步 starter&gt;</code></td></tr><tr><td>启动初始化器</td><td><code>&lt;Runner / Importer&gt;</code></td><td><code>&lt;初始化对象&gt;</code></td><td><code>&lt;幂等条件&gt;</code></td><td><code>&lt;启动阶段&gt;</code></td></tr></tbody></table><h2 id="_7-管理入口" tabindex="-1">7. 管理入口 <a class="header-anchor" href="#_7-管理入口" aria-label="Permalink to &quot;7. 管理入口&quot;">​</a></h2><p>说明菜单入口、权限资源、角色归口、租户边界和数据权限要求。 只写本模块的资源归属、默认授权和租户边界事实；长期权限、租户和数据权限规则只链接 <code>mango-pmo/rules/**</code>。</p><p>有后台页面、按钮权限或接口权限时，必须登记：</p><table tabindex="0"><thead><tr><th>菜单 / 页面</th><th>component key</th><th>权限码</th><th>入库来源</th><th>默认套餐 / 角色</th><th>后端校验入口</th></tr></thead><tbody><tr><td><code>&lt;菜单名称&gt;</code></td><td><code>&lt;module/page/index&gt;</code></td><td><code>&lt;module:resource:action&gt;</code></td><td><code>&lt;resource-manifest 或 migration&gt;</code></td><td><code>&lt;packageCodes / roleCodes&gt;</code></td><td><code>&lt;Controller / Service&gt;</code></td></tr></tbody></table><h2 id="_8-快速开始" tabindex="-1">8. 快速开始 <a class="header-anchor" href="#_8-快速开始" aria-label="Permalink to &quot;8. 快速开始&quot;">​</a></h2><p>列出业务开发者接入本模块时的最小依赖、最小配置、最小调用链路和常见误用防线。 只写本模块事实和接入示例；长期代码、测试、权限、租户和交付规则只链接 <code>mango-pmo/rules/**</code>。</p><h2 id="_9-返回字段" tabindex="-1">9. 返回字段 <a class="header-anchor" href="#_9-返回字段" aria-label="Permalink to &quot;9. 返回字段&quot;">​</a></h2><p>有对外返回对象时，列出业务最常用字段和是否建议业务入库。完整字段以 OpenAPI、类型定义或源码为准。</p><h2 id="_10-问题排查" tabindex="-1">10. 问题排查 <a class="header-anchor" href="#_10-问题排查" aria-label="Permalink to &quot;10. 问题排查&quot;">​</a></h2><p>记录常见错误、排查入口和已知限制。</p><h2 id="_11-相关文档" tabindex="-1">11. 相关文档 <a class="header-anchor" href="#_11-相关文档" aria-label="Permalink to &quot;11. 相关文档&quot;">​</a></h2><p>链接相关 <code>mango-pmo/rules/**</code> 规则源，不复制规则正文。 如有架构设计、历史方案、前端包或场景示例，在这里链接，不在使用文档里展开内部设计。</p>',31)])])}const g=e(r,[["render",l]]);export{s as __pageData,g as default};
